const listPatchesForEndpoint = `-- name: ListPatchesForEndpoint :many
SELECT
    p.id,
    p.name,
    p.version,
    p.severity,
    p.os_family,
    p.status,
    p.source_repo,
    p.created_at,
    dt.status AS deploy_status,
    COALESCE(
        (SELECT MAX(c.cvss_v3_score) FROM patch_cves pc JOIN cves c ON c.id = pc.cve_id WHERE pc.patch_id = p.id AND pc.tenant_id = $1),
        0
    )::real AS highest_cvss,
    COALESCE(
        (SELECT COUNT(*) FROM patch_cves pc WHERE pc.patch_id = p.id AND pc.tenant_id = $1),
        0
    )::bigint AS cve_count
FROM deployment_targets dt
JOIN patches p ON p.id = dt.patch_id
WHERE dt.endpoint_id = $2
  AND dt.tenant_id = $1
ORDER BY
    CASE p.severity
        WHEN 'critical' THEN 0
        WHEN 'high' THEN 1
        WHEN 'medium' THEN 2
        WHEN 'low' THEN 3
        ELSE 4
    END,
    p.name
LIMIT 1000
`

